import React, { useState } from "react";
import Link from "next/link";
import {
  User,
  Package,
  MessageSquare,
  FileText,
  LogOut,
  Moon,
  AlertCircle,
} from "lucide-react";

// Logout Confirmation Modal Component
const LogoutConfirmModal = ({ open, onClose, onConfirm }) => {
  if (!open) return null;

  return (
    <>
      {/* Modal Overlay */}
      <div
        className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center"
        onClick={onClose}
      >
        {/* Modal Content */}
        <div
          className="bg-white rounded-lg shadow-2xl w-96 p-6 mx-4"
          onClick={(e) => e.stopPropagation()}
        >
          {/* Icon */}
          <div className="flex justify-center mb-4">
            <div className="w-16 h-16 rounded-full bg-red-100 flex items-center justify-center">
              <AlertCircle className="w-8 h-8 text-red-600" />
            </div>
          </div>

          {/* Title */}
          <h3 className="text-xl font-semibold text-gray-900 text-center mb-2">
            Confirm Logout
          </h3>

          {/* Message */}
          <p className="text-gray-600 text-center mb-6">
            Are you sure you want to logout? You'll need to sign in again to
            access your account.
          </p>

          {/* Buttons */}
          <div className="flex gap-3">
            <button
              onClick={onClose}
              className="flex-1 px-4 py-2.5 border border-gray-300 rounded-lg text-gray-700 font-medium hover:bg-gray-50 transition-colors"
            >
              Cancel
            </button>
            <button
              onClick={onConfirm}
              className="flex-1 px-4 py-2.5 bg-red-600 text-white rounded-lg font-medium hover:bg-red-700 transition-colors"
            >
              Logout
            </button>
          </div>
        </div>
      </div>
    </>
  );
};

// Main ProfileMenu Component
const ProfileMenu = ({ open, onClose, user, onLogout }) => {
  const [showLogoutModal, setShowLogoutModal] = useState(false);

  const menuItems = [
    { icon: User, label: "My Profile", href: "/profile" },
    { icon: FileText, label: "My Losts", href: "/my-lost" },
    { icon: Package, label: "My Founds", href: "/my-found" },
    {
      icon: MessageSquare,
      label: "Messages",
      href: "/messages",
      badge: 3,
    },
  ];

  const handleLogoutClick = () => {
    setShowLogoutModal(true);
  };

  const handleLogoutConfirm = () => {
    setShowLogoutModal(false);
    onClose(); // Close sidebar
    onLogout(); // Execute logout
  };

  return (
    <>
      {/* Overlay */}
      {open && (
        <div className="fixed inset-0 bg-black/30 z-40" onClick={onClose} />
      )}

      {/* Sidebar */}
      <div
        className={`fixed top-0 right-0 h-screen w-80 bg-white z-50
        transform transition-transform duration-300 ease-in-out shadow-xl
        ${open ? "translate-x-0" : "translate-x-full"}`}
      >
        {/* Header */}
        <div className="px-6 py-5">
          <div className="flex items-center justify-between">
            <h2 className="text-lg font-semibold">Profile</h2>
            <button
              onClick={onClose}
              className="text-gray-500 hover:text-black text-xl"
            >
              ✕
            </button>
          </div>
        </div>

        {/* User Info */}
        <div className="px-6 py-5 border-b">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 rounded-full bg-indigo-600 text-white flex items-center justify-center font-semibold">
              {(user?.name || "U")[0].toUpperCase()}
            </div>
            <div>
              <p className="font-medium text-gray-900">{user?.name}</p>
              <p className="text-sm text-gray-500">{user?.email}</p>
            </div>
          </div>
        </div>

        {/* Menu Links */}
        <div className="px-6 py-4 space-y-1">
          {menuItems.map((item, i) => {
            const Icon = item.icon;
            return (
              <Link
                key={i}
                href={item.href}
                onClick={onClose}
                className="w-full flex items-center gap-3 px-4 py-3 rounded-lg hover:bg-gray-100 transition-colors"
              >
                <Icon className="w-5 h-5 text-gray-600" />
                <span className="text-gray-700 font-medium">{item.label}</span>

                {item.badge && (
                  <span className="ml-auto bg-red-500 text-white text-xs px-2 py-0.5 rounded-full">
                    {item.badge}
                  </span>
                )}
              </Link>
            );
          })}

          {/* Dark Mode (placeholder) */}
          <button className="w-full flex items-center gap-3 px-4 py-3 rounded-lg hover:bg-gray-100 transition-colors">
            <Moon className="w-5 h-5 text-gray-600" />
            <span className="text-gray-700 font-medium">Dark Mode</span>
          </button>
        </div>

        {/* Logout */}
        <div className="absolute bottom-0 w-full px-6 py-5 border-t">
          <button
            onClick={handleLogoutClick}
            className="w-full flex items-center gap-3 px-4 py-3 rounded-lg hover:bg-red-50 transition-colors"
          >
            <LogOut className="w-5 h-5 text-red-600" />
            <span className="text-red-600 font-semibold">Logout</span>
          </button>
        </div>
      </div>

      {/* Logout Confirmation Modal */}
      <LogoutConfirmModal
        open={showLogoutModal}
        onClose={() => setShowLogoutModal(false)}
        onConfirm={handleLogoutConfirm}
      />
    </>
  );
};

export default ProfileMenu;
